import pandas as pd, numpy as np
from sqlalchemy import text

# 复用已暂存的站点、污染、气象、企业与排放数据；不创建/覆盖最终输出变量。
station60_combined_influence_notes = []
station60_analysis_window_label = f"{window_start_station60}至{window_end_station60}（起始含、结束不含）"

# 1) 站点PM10/AQI时间序列：优先使用统计代理已筛选窗口
aq_df = station60_stats_window_df.copy()
if 'timestamp' in aq_df.columns:
    aq_df['timestamp'] = pd.to_datetime(aq_df['timestamp'])
else:
    station60_combined_influence_notes.append("站点小时污染数据缺少timestamp字段，无法开展逐小时耦合分析。")
aq_cols = [c for c in ['timestamp','pm10','aqi','pm2_5','so2','no2','co','o3'] if c in aq_df.columns]
aq_ts = aq_df[aq_cols].copy() if 'timestamp' in aq_df.columns else pd.DataFrame()
if not aq_ts.empty:
    aq_ts = aq_ts.sort_values('timestamp').drop_duplicates('timestamp')

# 2) 气象：优先区县小时气象，缺失则用城市小时气象
weather_source = None
weather_df = pd.DataFrame()
if isinstance(station60_hourly_district_weather_df, pd.DataFrame) and not station60_hourly_district_weather_df.empty:
    weather_df = station60_hourly_district_weather_df.copy()
    weather_source = "区县小时气象"
elif isinstance(station60_hourly_city_weather_df, pd.DataFrame) and not station60_hourly_city_weather_df.empty:
    weather_df = station60_hourly_city_weather_df.copy()
    weather_source = "城市小时气象"
else:
    station60_combined_influence_notes.append("分析窗口内未发现可用的区县或城市小时气象数据。")

if not weather_df.empty:
    weather_df['timestamp'] = pd.to_datetime(weather_df['timestamp'])
    w_keep = [c for c in ['timestamp','temperature','humidity','wind_speed','wind_degree','wind_direction','wind_scale'] if c in weather_df.columns]
    weather_ts = weather_df[w_keep].sort_values('timestamp').drop_duplicates('timestamp')
else:
    weather_ts = pd.DataFrame()

# 3) 企业排放：聚合相关企业小时排放
em_df = station60_hourly_company_emissions_df.copy() if isinstance(station60_hourly_company_emissions_df, pd.DataFrame) else pd.DataFrame()
if not em_df.empty and 'timestamp' in em_df.columns:
    em_df['timestamp'] = pd.to_datetime(em_df['timestamp'])
    em_numeric_cols = [c for c in ['exhaust_gas','nox','so2','pm','hc','nmhc','co','hcl'] if c in em_df.columns]
    station60_hourly_relevant_company_emissions_agg_df = (
        em_df.groupby('timestamp', as_index=False)[em_numeric_cols].sum(min_count=1)
             .rename(columns={c: f"company_total_{c}" for c in em_numeric_cols})
             .sort_values('timestamp')
    )
else:
    station60_hourly_relevant_company_emissions_agg_df = pd.DataFrame()
    station60_combined_influence_notes.append("分析窗口内未发现相关企业小时排放数据，或排放数据缺少timestamp字段。")

# 4) 合并逐小时数据并计算同步/滞后相关
if not aq_ts.empty:
    station60_emission_weather_hourly_analysis_df = aq_ts.copy()
    if not weather_ts.empty:
        station60_emission_weather_hourly_analysis_df = station60_emission_weather_hourly_analysis_df.merge(weather_ts, on='timestamp', how='left')
    if not station60_hourly_relevant_company_emissions_agg_df.empty:
        station60_emission_weather_hourly_analysis_df = station60_emission_weather_hourly_analysis_df.merge(station60_hourly_relevant_company_emissions_agg_df, on='timestamp', how='left')
else:
    station60_emission_weather_hourly_analysis_df = pd.DataFrame()

corr_rows = []
if not station60_emission_weather_hourly_analysis_df.empty and 'pm10' in station60_emission_weather_hourly_analysis_df.columns:
    candidate_vars = [c for c in ['aqi','pm2_5','so2','no2','co','o3','temperature','humidity','wind_speed','wind_degree',
                                  'company_total_pm','company_total_nox','company_total_so2','company_total_exhaust_gas','company_total_co']
                      if c in station60_emission_weather_hourly_analysis_df.columns]
    base = station60_emission_weather_hourly_analysis_df.sort_values('timestamp').copy()
    for v in candidate_vars:
        valid = base[['pm10', v]].dropna()
        if len(valid) >= 3 and valid['pm10'].nunique() > 1 and valid[v].nunique() > 1:
            corr_rows.append({"factor": v, "lag_hours": 0, "pearson_r": float(valid['pm10'].corr(valid[v])), "n": int(len(valid))})
    # 企业排放前置1-3小时与当前PM10的关系：排放变量shift为历史值
    for v in [c for c in candidate_vars if c.startswith('company_total_')]:
        for lag in [1,2,3]:
            tmp = base[['timestamp','pm10',v]].copy()
            tmp[f'{v}_lag{lag}h'] = tmp[v].shift(lag)
            valid = tmp[['pm10', f'{v}_lag{lag}h']].dropna()
            if len(valid) >= 3 and valid['pm10'].nunique() > 1 and valid[f'{v}_lag{lag}h'].nunique() > 1:
                corr_rows.append({"factor": v, "lag_hours": lag, "pearson_r": float(valid['pm10'].corr(valid[f'{v}_lag{lag}h'])), "n": int(len(valid))})
station60_pm10_weather_emission_correlations_df = pd.DataFrame(corr_rows).sort_values(['lag_hours','factor']) if corr_rows else pd.DataFrame(columns=['factor','lag_hours','pearson_r','n'])

# 5) 企业-站点空间/风向耦合：如暂存企业表缺少距离或方位，则使用已解析station_id_60与企业id一次性计算；严格使用geography距离/方位，不转换geometry。
comp_df = station60_relevant_companies_df.copy() if isinstance(station60_relevant_companies_df, pd.DataFrame) else pd.DataFrame()
station60_company_source_receptor_df = pd.DataFrame()
if not comp_df.empty:
    id_col = 'company_id' if 'company_id' in comp_df.columns else ('id' if 'id' in comp_df.columns else None)
    if id_col is not None:
        company_ids = [int(x) for x in comp_df[id_col].dropna().unique().tolist()]
        if company_ids:
            station60_company_spatial_sql = text("""
                SELECT pc.id AS company_id,
                       pc.industry_type::text AS industry_type,
                       ST_Distance(pc.coordinate, aqs.coordinate)/1000.0 AS distance_km,
                       degrees(ST_Azimuth(pc.coordinate, aqs.coordinate)) AS bearing_company_to_station_deg
                FROM polluting_company pc
                JOIN air_quality_station aqs ON aqs.id = :station_id
                WHERE pc.id = ANY(:company_ids)
            """)
            station60_company_source_receptor_df = pd.read_sql(
                station60_company_spatial_sql, engine,
                params={"station_id": int(station_id_60), "company_ids": company_ids}
            )
else:
    station60_combined_influence_notes.append("未发现已暂存的相关企业清单，无法开展企业-站点空间耦合分析。")

# 将企业排放总量汇入企业空间表
if not station60_company_source_receptor_df.empty and not em_df.empty and 'company_id' in em_df.columns:
    em_tot_cols = [c for c in ['pm','nox','so2','exhaust_gas','co'] if c in em_df.columns]
    em_by_company = em_df.groupby('company_id', as_index=False)[em_tot_cols].sum(min_count=1).rename(columns={c: f'window_total_{c}' for c in em_tot_cols})
    station60_company_source_receptor_df = station60_company_source_receptor_df.merge(em_by_company, on='company_id', how='left')

# 风向对准判别：风向为“来向”，输送去向=(wind_degree+180)%360；若输送去向接近“企业->站点”方位，则有利于企业影响站点
def _angle_diff_deg(a, b):
    return abs((a - b + 180) % 360 - 180)

station60_wind_alignment_hourly_df = pd.DataFrame()
station60_wind_alignment_summary = {}
if (not station60_company_source_receptor_df.empty and
    not weather_ts.empty and 'wind_degree' in weather_ts.columns and
    weather_ts['wind_degree'].notna().any()):
    companies_for_align = station60_company_source_receptor_df[['company_id','industry_type','distance_km','bearing_company_to_station_deg']].dropna(subset=['bearing_company_to_station_deg']).copy()
    if not companies_for_align.empty:
        wh = weather_ts[['timestamp','wind_degree','wind_speed','wind_direction'] if 'wind_direction' in weather_ts.columns else ['timestamp','wind_degree','wind_speed']].copy()
        wh['transport_to_deg'] = (wh['wind_degree'] + 180) % 360
        wh['_k'] = 1
        companies_for_align['_k'] = 1
        align = wh.merge(companies_for_align, on='_k', how='inner').drop(columns=['_k'])
        align['wind_to_company_station_angle_diff_deg'] = align.apply(lambda r: _angle_diff_deg(r['transport_to_deg'], r['bearing_company_to_station_deg']), axis=1)
        align['aligned_45deg'] = align['wind_to_company_station_angle_diff_deg'] <= 45
        align['aligned_30deg'] = align['wind_to_company_station_angle_diff_deg'] <= 30
        if 'wind_speed' in align.columns:
            align['ventilation_class'] = pd.cut(align['wind_speed'], bins=[-np.inf,1.5,3.3,np.inf], labels=['低风速','中等风速','较高风速'])
        station60_wind_alignment_hourly_df = align
        station60_wind_alignment_summary = {
            "company_count_evaluated": int(companies_for_align['company_id'].nunique()),
            "hour_count_with_wind": int(wh['timestamp'].nunique()),
            "company_hour_pairs": int(len(align)),
            "aligned_45deg_pairs": int(align['aligned_45deg'].sum()),
            "aligned_45deg_share": float(align['aligned_45deg'].mean()) if len(align) else np.nan,
            "aligned_30deg_pairs": int(align['aligned_30deg'].sum()),
            "aligned_30deg_share": float(align['aligned_30deg'].mean()) if len(align) else np.nan,
        }
        if not aq_ts.empty:
            aligned_by_hour = align.groupby('timestamp', as_index=False).agg(
                aligned_company_count_45deg=('aligned_45deg','sum'),
                min_angle_diff_deg=('wind_to_company_station_angle_diff_deg','min')
            )
            pm_align = aq_ts[['timestamp','pm10']].merge(aligned_by_hour, on='timestamp', how='inner')
            if len(pm_align.dropna()) >= 3 and pm_align['pm10'].nunique() > 1 and pm_align['aligned_company_count_45deg'].nunique() > 1:
                station60_wind_alignment_summary["pm10_vs_aligned_company_count_r"] = float(pm_align['pm10'].corr(pm_align['aligned_company_count_45deg']))
            if len(pm_align.dropna()) >= 3 and pm_align['pm10'].nunique() > 1 and pm_align['min_angle_diff_deg'].nunique() > 1:
                station60_wind_alignment_summary["pm10_vs_min_angle_diff_r"] = float(pm_align['pm10'].corr(pm_align['min_angle_diff_deg']))
    else:
        station60_combined_influence_notes.append("相关企业缺少可用企业至站点方位角，无法进行风向对准判别。")
else:
    if weather_ts.empty or 'wind_degree' not in weather_ts.columns or not weather_ts.get('wind_degree', pd.Series(dtype=float)).notna().any():
        station60_combined_influence_notes.append("气象数据缺少可用风向角，无法进行风向对准判别。")
    if station60_company_source_receptor_df.empty:
        station60_combined_influence_notes.append("企业空间信息为空，无法进行风向对准判别。")

# 6) 峰值时段与非峰值对比
station60_pm10_peak_context = {}
if not station60_emission_weather_hourly_analysis_df.empty and 'timestamp' in station60_emission_weather_hourly_analysis_df.columns:
    peak_ts = pd.to_datetime(station60_stats_peak_pm10_timestamp)
    peak_row = station60_emission_weather_hourly_analysis_df[station60_emission_weather_hourly_analysis_df['timestamp'] == peak_ts]
    if not peak_row.empty:
        peak_rec = peak_row.iloc[0]
        station60_pm10_peak_context = {
            "peak_timestamp": peak_ts,
            "peak_pm10": float(station60_stats_max_pm10_value),
            "mean_pm10_from_staged_stats": float(station60_stats_mean_pm10_value),
            "mean_aqi_from_staged_stats": float(station60_stats_mean_aqi_value),
            "peak_offset_hours_from_staged_stats": int(station60_stats_peak_pm10_offset_hours_value),
        }
        for c in ['aqi','humidity','wind_speed','wind_degree','temperature','company_total_pm','company_total_nox','company_total_so2','company_total_exhaust_gas']:
            if c in peak_row.columns and pd.notna(peak_rec.get(c)):
                vals = station60_emission_weather_hourly_analysis_df[c].dropna()
                station60_pm10_peak_context[f"peak_{c}"] = float(peak_rec[c]) if np.issubdtype(type(peak_rec[c]), np.number) else peak_rec[c]
                if len(vals) > 0 and np.issubdtype(vals.dtype, np.number):
                    station60_pm10_peak_context[f"window_mean_{c}"] = float(vals.mean())

# 7) 形成供综合代理复用的结构化结论
top_corrs = []
if not station60_pm10_weather_emission_correlations_df.empty:
    tmpc = station60_pm10_weather_emission_correlations_df.copy()
    tmpc['abs_r'] = tmpc['pearson_r'].abs()
    top_corrs = tmpc.sort_values('abs_r', ascending=False).head(8).drop(columns='abs_r').to_dict('records')

company_summary = {}
if not station60_company_source_receptor_df.empty:
    company_summary = {
        "company_count": int(station60_company_source_receptor_df['company_id'].nunique()),
        "distance_km_min": float(station60_company_source_receptor_df['distance_km'].min()) if 'distance_km' in station60_company_source_receptor_df else None,
        "distance_km_median": float(station60_company_source_receptor_df['distance_km'].median()) if 'distance_km' in station60_company_source_receptor_df else None,
        "distance_km_max": float(station60_company_source_receptor_df['distance_km'].max()) if 'distance_km' in station60_company_source_receptor_df else None,
    }
    if 'window_total_pm' in station60_company_source_receptor_df.columns:
        company_summary["window_total_company_pm_kg"] = float(station60_company_source_receptor_df['window_total_pm'].sum(skipna=True))
    if 'industry_type' in station60_company_source_receptor_df.columns:
        company_summary["industry_type_counts"] = station60_company_source_receptor_df['industry_type'].value_counts(dropna=False).to_dict()

weather_summary = {}
if not weather_ts.empty:
    for c in ['wind_speed','humidity','temperature','wind_degree']:
        if c in weather_ts.columns and weather_ts[c].notna().any():
            weather_summary[f"{c}_mean"] = float(weather_ts[c].mean())
            weather_summary[f"{c}_min"] = float(weather_ts[c].min())
            weather_summary[f"{c}_max"] = float(weather_ts[c].max())
    if 'wind_direction' in weather_ts.columns:
        weather_summary["wind_direction_counts"] = weather_ts['wind_direction'].value_counts(dropna=False).to_dict()

station60_emission_meteorology_pm10_influence_for_synthesis = {
    "analysis_window": station60_analysis_window_label,
    "pollution_metrics_from_staged_stats": {
        "mean_pm10": float(station60_stats_mean_pm10_value),
        "max_pm10": float(station60_stats_max_pm10_value),
        "mean_aqi": float(station60_stats_mean_aqi_value),
        "peak_pm10_offset_hours": int(station60_stats_peak_pm10_offset_hours_value),
        "peak_pm10_timestamp": pd.to_datetime(station60_stats_peak_pm10_timestamp),
        "valid_hour_count": int(station60_stats_valid_count),
    },
    "weather_source": weather_source,
    "weather_summary": weather_summary,
    "company_summary": company_summary,
    "wind_alignment_summary": station60_wind_alignment_summary,
    "top_pm10_correlations": top_corrs,
    "peak_context": station60_pm10_peak_context,
    "data_limitations": station60_combined_influence_notes,
}

print("站点60工业排放-气象-PM10耦合分析已完成。")
print("窗口:", station60_analysis_window_label)
print("有效污染小时数:", station60_stats_valid_count, "PM10均值:", round(float(station60_stats_mean_pm10_value), 3), "PM10峰值:", round(float(station60_stats_max_pm10_value), 3), "峰值滞后小时:", int(station60_stats_peak_pm10_offset_hours_value))
print("气象来源:", weather_source, "气象小时数:", 0 if weather_ts.empty else int(weather_ts['timestamp'].nunique()))
print("相关企业数:", company_summary.get("company_count", 0), "企业排放聚合小时数:", 0 if station60_hourly_relevant_company_emissions_agg_df.empty else int(station60_hourly_relevant_company_emissions_agg_df['timestamp'].nunique()))
print("风向对准摘要:", station60_wind_alignment_summary if station60_wind_alignment_summary else "无可用风向对准结果")
print("最强相关因子前8项:", top_corrs if top_corrs else "无可计算相关（样本不足或变量无变化）")
print("数据限制:", station60_combined_influence_notes if station60_combined_influence_notes else "未发现关键缺失")
